DO $$ BEGIN CREATE INDEX IF NOT EXISTS idx_watchlist_active ON watchlist_entities (active) WHERE active = true; CREATE INDEX IF NOT EXISTS idx_watchlist_category ON watchlist_entities (category); CREATE INDEX IF NOT EXISTS idx_raw_unprocessed ON raw_items (processed, created_at DESC) WHERE processed = false; CREATE INDEX IF NOT EXISTS idx_raw_published ON raw_items (published_at DESC); CREATE INDEX IF NOT EXISTS idx_raw_source_type ON raw_items (source_type); CREATE INDEX IF NOT EXISTS idx_events_published ON events (published_at DESC); CREATE INDEX IF NOT EXISTS idx_events_unpushed ON events (pushed_to_tg, importance) WHERE pushed_to_tg = false; CREATE INDEX IF NOT EXISTS idx_events_daily ON events (included_in_daily, published_at DESC) WHERE included_in_daily = false; CREATE INDEX IF NOT EXISTS idx_events_weekly ON events (included_in_weekly, published_at DESC) WHERE included_in_weekly = false; CREATE INDEX IF NOT EXISTS idx_events_category ON events (category); CREATE INDEX IF NOT EXISTS idx_events_importance ON events (importance); CREATE INDEX IF NOT EXISTS idx_pipeline_runs_type ON pipeline_runs (pipeline_type, started_at DESC); END $$;
